const payload = $input.first().json;

// Extract contact data from GHL webhook
const contact = payload.contact || payload;

return [{
  json: {
    contact: {
      id: contact.id || contact.contact_id,
      email: contact.email || contact.email_address,
      phone: contact.phone || contact.phone_number,
      firstName: contact.firstName || contact.first_name,
      lastName: contact.lastName || contact.last_name,
      locationId: contact.locationId || contact.location_id || payload.locationId,
      source: 'ghl_webhook'
    },
    original_event: payload.type || 'contact.created'
  }
}];

const response = $input.first().json;
console.log('Dashboard enrichment response:', JSON.stringify(response));
return [$input.first()];
